import { Component, ViewChild, ElementRef, OnInit } from '@angular/core';
import { UntypedFormControl, Validators } from '@angular/forms';
import { MatDialog as MatDialog, MatDialogRef as MatDialogRef } from '@angular/material/dialog';
import { MAT_DIALOG_DATA as MAT_DIALOG_DATA } from '@angular/material/dialog';
import { Inject } from '@angular/core';
import { stdService } from '../../../helpers/services/std.service';
import { Observable } from 'rxjs';
import { firstValueFrom } from 'rxjs';
import { map, startWith } from 'rxjs/operators';
import { MatSnackBar } from '@angular/material/snack-bar';
import { itemService } from '../../../helpers/services/main.service';
export interface DialogData {
  selectedRow: {
    data
  }
}

@Component({
    selector: 'DuplicateDialog',
    templateUrl: 'duplicate_dialog.component.html',
    styleUrls: ['duplicate_dialog.component.scss'],
    standalone: false
})
export class DuplicateDialogComponent implements OnInit {
  divisionControler = new UntypedFormControl(null, [Validators.required]);
  licenseControler = new UntypedFormControl(null, [Validators.required]);
  RFQGroupControler = new UntypedFormControl(null, [Validators.required]);
  options: string[] = [];
  filteredOptions: Observable<any[]>;
  divisionOptions: Observable<any[]>;
  RFQGroupOptions: Observable<any[]>;
  licenseOptions: Observable<any[]>;
  colHeaders: any = []
  selectedRFQGroup: any
  selectOpen = false;
  loading = false;
  newItemSection = false
  myControl = new UntypedFormControl();
  license: any[] = [];
  division: any[] = [];
  RFQGroup: any[] = [];
  selectedDivisionCode: any = [];
  selectedLicense: any = [];
  constructor(private itemService: itemService, private _snackBar: MatSnackBar, public dialog: MatDialog, @Inject(MAT_DIALOG_DATA) public data: DialogData, private stdService: stdService, public dialogRef: MatDialogRef<DuplicateDialogComponent>) {

  }
  async ngOnInit() {
    await this.itemService
    .getGridHeader({ grid_id: 'rfq' })
    .subscribe(async (colHeaders: any) => {
      this.colHeaders = colHeaders
    })
    try {
      const data: any = await firstValueFrom(this.itemService.getRFQGroup());
      for (var i = 0; data.length > i; i++) {
        this.RFQGroup[i] = data[i]
      }
      this.RFQGroupOptions = this.RFQGroupControler.valueChanges.pipe(
        startWith(''),
        map(value => (typeof value === 'string' ? value : value)),
        map(value => (value ? this._filter(value, this.RFQGroup) : this.RFQGroup.slice())),
      );
    } catch (err) {
      console.error('[DuplicateDialog] getRFQGroup failed:', err);
    }

  }

  async onBtAdd() {
    let newItem =  this.data.selectedRow[0].data
    const copyAllowed = await (async () => {
      if (typeof window['ensureRfqCopyAllowed'] === 'function') {
        return window['ensureRfqCopyAllowed'](newItem, this.itemService, this._snackBar);
      }
      return true;
    })();
    if (!copyAllowed) {
      return;
    }
    this.loading = true;
    if (newItem) {
      if (this.selectedRFQGroup) {
        newItem.old_id = newItem.id
        newItem['RFQ Group'] = this.selectedRFQGroup
        newItem["Div"] = { title:  newItem["Div"] }
        newItem['Price Code'] = DuplicateDialogComponent.buildDuplicatePriceCode(newItem['Price Code']);
        newItem['rfq_container_id_fk'] = 1
        newItem.id = null
        try {
          const data: any = await firstValueFrom(this.itemService.addRfqItem({ data: newItem, copyVendors: true }));
          //add vendor
          this.dialogRef.close(newItem);
        } catch (err) {
          console.error('[DuplicateDialog] addRfqItem failed:', err);
        }
      }else{
        this._snackBar.open('Please select RFQ Group', 'Close')
      }
    }
  }


  onBtCancel() {
    this.dialogRef.close();
  }
  private _filter(value: any, data): any[] {
    let filterValue;
    if (value.title) {
      filterValue = value.title.toLowerCase();
    } else {
      filterValue = value.toLowerCase();
    }
    if (data[0].RFQGroup_name) {
      return data.filter(data => data.RFQGroup_name.toLowerCase().includes(filterValue));
    } else {
      return data.filter(data => data.title.toLowerCase().includes(filterValue));
    }

  }
  displayFn(data: any) {
    if (data) {
      if (data.title) {
        return data.title && data.title ? data.title : '';
      } else {
        return data && data ? data : '';
      }
    }
  }


  async onSave(value) {
    try {
      const data: any = await firstValueFrom(this.itemService.addNewRFQGroup({ value: value }));
      this.RFQGroup.push(data)
      this.RFQGroupOptions = this.RFQGroupControler.valueChanges.pipe(
        startWith(''),
        map(value => (typeof value === 'string' ? value : value)),
        map(value => (value ? this._filter(value, this.RFQGroup) : this.RFQGroup.slice())),
      );
    } catch (err) {
      console.error('[DuplicateDialog] addNewRFQGroup failed:', err);
    }
    this.newItemSection = false
  }

  setEquationToNull(newItem) {
    newItem[this.getMasterFiledName('gen_fob_sell_price')] = null
    newItem[this.getMasterFiledName('gen_fob_margin')] = null
    newItem[this.getMasterFiledName('gen_fob_price_sales')] = null
    newItem[this.getMasterFiledName('gen_poe_sell_price')] = null
    newItem[this.getMasterFiledName('gen_poe_margin')] = null
    newItem[this.getMasterFiledName('gen_poe_price_sales')] = null
    newItem[this.getMasterFiledName('gen_whse_sell_price')] = null
    newItem[this.getMasterFiledName('gen_whse_margin')] = null
    newItem[this.getMasterFiledName('gen_whse_price_sales')] = null
    newItem[this.getMasterFiledName('gen_mddp_sell_price')] = null
    newItem[this.getMasterFiledName('gen_mddp_margin')] = null
    newItem[this.getMasterFiledName('gen_mddp_price_sales')] = null
    newItem[this.getMasterFiledName('lic_fob_sell_price')] = null
    newItem[this.getMasterFiledName('lic_fob_margin')] = null
    newItem[this.getMasterFiledName('lic_fob_price_sales')] = null
    newItem[this.getMasterFiledName('lic_poe_sell_price')] = null
    newItem[this.getMasterFiledName('lic_poe_margin')] = null
    newItem[this.getMasterFiledName('lic_poe_price_sales')] = null
    newItem[this.getMasterFiledName('lic_whse_sell_price')] = null
    newItem[this.getMasterFiledName('lic_whse_margin')] = null
    newItem[this.getMasterFiledName('lic_whse_price_sales')] = null
    newItem[this.getMasterFiledName('lic_mddp_sell_price')] = null
    newItem[this.getMasterFiledName('lic_mddp_margin')] = null
    newItem[this.getMasterFiledName('lic_mddp_price_sales')] = null
    newItem[this.getMasterFiledName('lic_fob_royalty')] = null
  }
  getMasterFiledName(colId) {
    for (var i = 0; this.colHeaders.length > i; i++) {
      if (this.colHeaders[i].col_id == colId) {
        return this.colHeaders[i].field
      }
    }
  }
}

