import { describe, expect, it } from '@jest/globals';
import {
  deriveToStatus, ORIGIN_DEFAULTS, statusLabel,
  directionLabel, boxRouteLabel, legTypeForBox, BOX_ROUTES
} from './sample.status';

describe('sample.status ORIGIN_DEFAULTS', () => {
  it('maps factory origins inbound and usa_bought outbound', () => {
    expect(ORIGIN_DEFAULTS.factory_request).toEqual({ direction: 'inbound', initialStatus: 'requested' });
    expect(ORIGIN_DEFAULTS.factory_offer.direction).toBe('inbound');
    expect(ORIGIN_DEFAULTS.usa_bought).toEqual({ direction: 'outbound', initialStatus: 'nyc_requested' });
    expect(ORIGIN_DEFAULTS.customer).toEqual({ direction: 'customer', initialStatus: 'ningbo_checked_in' });
  });
});

describe('sample.status deriveToStatus', () => {
  it('advances inbound shipped -> ningbo on check_in at Ningbo', () => {
    expect(deriveToStatus({ direction: 'inbound', currentStatus: 'shipped', office: 'Ningbo', eventType: 'check_in' }))
      .toEqual({ ok: true, toStatus: 'ningbo_checked_in' });
  });

  it('rejects inbound check_in at the wrong office', () => {
    const r = deriveToStatus({ direction: 'inbound', currentStatus: 'shipped', office: 'NYC', eventType: 'check_in' });
    expect(r.ok).toBe(false);
  });

  it('advances outbound nyc_requested -> nyc_checked_out on check_out at NYC', () => {
    expect(deriveToStatus({ direction: 'outbound', currentStatus: 'nyc_requested', office: 'NYC', eventType: 'check_out' }).toStatus)
      .toBe('nyc_checked_out');
  });

