import { describe, expect, it } from '@jest/globals';
import { DuplicateDialogComponent } from './duplicate_dialog.component';

describe('DuplicateDialogComponent.buildDuplicatePriceCode', () => {
  const SUFFIX = /_DP_[A-Z0-9]{5}$/;

  it('appends _DP_ plus a 5-char uppercase suffix to a fresh code', () => {
    const result = DuplicateDialogComponent.buildDuplicatePriceCode('ABC123');
    expect(result).toMatch(/^ABC123_DP_[A-Z0-9]{5}$/);
    // exactly 9 characters added
    expect(result.length).toBe('ABC123'.length + 9);
  });

  it('strips an existing _DP_ tail instead of stacking suffixes', () => {
    const once = DuplicateDialogComponent.buildDuplicatePriceCode('ABC123');
    const twice = DuplicateDialogComponent.buildDuplicatePriceCode(once);
    const thrice = DuplicateDialogComponent.buildDuplicatePriceCode(twice);

    // base is always restored to the original before re-appending
    expect(twice).toMatch(/^ABC123_DP_[A-Z0-9]{5}$/);
    expect(thrice).toMatch(/^ABC123_DP_[A-Z0-9]{5}$/);

    // length never grows past base + one suffix, no matter how many copies
    expect(thrice.length).toBe('ABC123'.length + 9);
  });

  it('does not strip _DP_-like text that is not the 5-char tail pattern', () => {
    // e.g. embedded mid-code or wrong length should be preserved as base
    const result = DuplicateDialogComponent.buildDuplicatePriceCode('PART_DP_LONGER');
    expect(result).toMatch(/^PART_DP_LONGER_DP_[A-Z0-9]{5}$/);
  });

  it('handles null/undefined/empty input without throwing', () => {
    expect(DuplicateDialogComponent.buildDuplicatePriceCode(null as any)).toMatch(/^_DP_[A-Z0-9]{5}$/);
    expect(DuplicateDialogComponent.buildDuplicatePriceCode(undefined as any)).toMatch(/^_DP_[A-Z0-9]{5}$/);
    expect(DuplicateDialogComponent.buildDuplicatePriceCode('')).toMatch(/^_DP_[A-Z0-9]{5}$/);
  });

  it('produces a value matching the unique-suffix contract', () => {
    expect(DuplicateDialogComponent.buildDuplicatePriceCode('X')).toMatch(SUFFIX);
  });
});

